tinymce.PluginManager.add("floor",function(editor,url){var openDialog=function(){var win;win=editor.windowManager.open({title:"Wstaw galerię",file:tinyMCE.baseURL+"/plugins/floor/dialog.php?editor="+editor.id+"&lang="+tinymce.settings.language+"&subfolder="+tinymce.settings.subfolder,body:{type:"panel",classes:"myClassname",items:[{type:"htmlpanel",html:'<div id="floor" class="row pt-3 pb-3 m-0"></div>'}]},size:"large",buttons:[]});$.ajax({type:"GET",url:"/admin/ajaxGetGalleries",success:function(result){console.log(result);$.each(result,function(i,item){$('<div class="col-3">'+'<div class="card">'+'<div class="card-body">'+'<h5 class="card-title">'+item.name+"</h5>"+'<div class="dropdown">'+'<button class="btn btn-secondary btn-sm dropdown-toggle" type="button" id="dropdownMenuButton" data-bs-toggle="dropdown" aria-haspopup="true" aria-expanded="false"> Wstaw jako </button>'+'<div class="dropdown-menu" aria-labelledby="dropdownMenuButton">'+'<span class="dropdown-item" data-type="gallery" data-id="'+item.id+'">Galeria</span>'+'<span class="dropdown-item" data-type="carousel" data-id="'+item.id+'">Karuzela</span>'+'<span class="dropdown-item" data-type="slider" data-id="'+item.id+'">Slider</span>'+"</div>"+"</div>"+"</div>"+"</div>"+"</div>").appendTo("#gallery")});$(".dropdown-item").on("click",function(){const type=$(this).attr("data-type");const id=$(this).attr("data-id");tinymce.activeEditor.execCommand("mceInsertContent",false,"<p>[galeria="+type+"]"+id+"[/galeria]</p>");editor.windowManager.close()})},error:function(){alert("Wystąpił błąd połączenia z bazą")}})};editor.ui.registry.addIcon("floor-list",'<svg viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg" fill="#000000"><g id="SVGRepo_bgCarrier" stroke-width="0"></g><g id="SVGRepo_tracerCarrier" stroke-linecap="round" stroke-linejoin="round"></g><g id="SVGRepo_iconCarrier"><path fill-rule="evenodd" clip-rule="evenodd" d="M7.62706 1.08717L8.18535 1.08325L14.2762 5.1203L14.2727 5.95617L8.1818 9.91912L7.63062 9.91528L1.72152 5.95233L1.71796 5.12422L7.62706 1.08717ZM7.91335 2.10268L2.89198 5.53323L7.91329 8.90079L13.0891 5.5332L7.91335 2.10268ZM1.79257 8.5L7.63059 12.4153L8.18177 12.4191L14.2053 8.5H12.3716L7.91326 11.4008L3.58794 8.5H1.79257ZM7.63059 14.9153L1.79257 11H3.58794L7.91326 13.9008L12.3716 11H14.2053L8.18177 14.9191L7.63059 14.9153Z"></path></g></svg>');editor.ui.registry.addButton("floor",{icon:"floor-list",tooltip:"Dodaj listę mieszkań z piętra",onAction:function(){openDialog()}})});